INSERT INTO failure_diagnoses (id, cluster_id, status, provider, model, category, confidence, summary, root_cause, details, error, input_tokens, output_tokens, duration_ms, created_at, updated_at) VALUES (1, 1, 'completed', 'demo', 'demo', 'infrastructure', 'high', 'Checkout button click times out consistently — suspected slow CI agent or network latency spike causing locator resolution delay.', 'The locator.click timeout (30 000 ms) is exceeded when the checkout page renders slowly on the CI runner. The root cause is a missing explicit wait for the payment form to become interactive before clicking, combined with CI infrastructure variability.', '{"confidenceScore":82,"severity":"high","affectedArea":"checkout / payment","hypotheses":[{"category":"infrastructure","likelihood":82,"rootCause":"Slow CI runner renders the payment form too late; locator.click exceeds the 30s timeout before the button becomes interactive.","evidence":["Failure rate correlates with high-load CI runs (build numbers 1180-1200) [recurrenceFlakiness]","Element present in DOM but not interactive at click time [steps]"]},{"category":"test-bug","likelihood":40,"rootCause":"The test clicks without an explicit wait for the payment form to be ready.","evidence":["No waitFor/waitForLoadState precedes the click [testSource]"]}],"investigationSteps":["Re-run the cluster on a low-load runner to confirm CI variability is the driver","Check whether the payment form fires a network-idle event before becoming interactive"],"evidence":["TimeoutError occurs at tests/checkout/checkout.spec.ts:42 in both affected tests","Error fires during locator.click — the element is present in DOM but not yet interactive","Failure rate correlates with high-load CI runs (build numbers 1180-1200)"],"suggestedFix":{"description":"Add an explicit waitForLoadState(\"networkidle\") or waitFor condition before the click, and increase the locator timeout for the payment button to 60 000 ms.","file":"tests/checkout/checkout.spec.ts","code":"await page.waitForLoadState(\"networkidle\");\nawait page.getByRole(\"button\", { name: \"Pay\" }).click({ timeout: 60000 });"},"preventionTips":["Use page.waitForLoadState() before interacting with dynamically loaded payment forms","Add a CI-aware timeout multiplier for payment-related actions","Consider adding a Playwright expect.poll for the button to have aria-disabled=false"]}', NULL, 1240, 380, 2850, 1745573400, 1745573400);
INSERT INTO failure_diagnoses (id, cluster_id, status, provider, model, category, confidence, summary, root_cause, details, error, input_tokens, output_tokens, duration_ms, created_at, updated_at) VALUES (2, 3, 'completed', 'demo', 'demo', 'app-bug', 'high', 'POST /auth/login and related auth tests fail with HTTP 500 — server-side exception in the authentication handler.', 'The authentication endpoint returns HTTP 500 instead of the expected 200, causing the assertion expect(received).toBe(200).toBe(500) to fail. This indicates a regression in the auth service — likely an unhandled exception in the login handler introduced in recent commits.', '{"confidenceScore":90,"severity":"blocker","affectedArea":"authentication / login","hypotheses":[{"category":"app-bug","likelihood":90,"rootCause":"The /auth/login handler throws an unhandled exception introduced in the auth refactor, returning HTTP 500 instead of 200.","evidence":["Expected: 200 / Received: 500 in two separate auth test cases [executionError]","Error started appearing in builds after the auth refactor commits [scmInvestigation]"]}],"investigationSteps":["Inspect server logs for the stack trace behind the 500 on POST /auth/login","Bisect the auth refactor commits to find the breaking change"],"evidence":["Expected: 200 / Received: 500 in two separate auth test cases","Both failures share the same cluster fingerprint, confirming a single root cause","The error started appearing in builds after the auth refactor commits"],"suggestedFix":{"description":"Inspect the /auth/login endpoint for unhandled exceptions. Add error handling around the credential verification logic and ensure the response status code is correctly set for each code path.","file":"tests/api/auth.spec.ts","code":null},"preventionTips":["Add integration tests that exercise the auth endpoint with a real DB connection","Set up error monitoring (Sentry, Datadog) on the /auth/login endpoint to catch 5xx regressions early","Add a smoke test in CI that hits /auth/login before the full test suite"]}', NULL, 980, 310, 2100, 1745573400, 1745573400);
INSERT INTO failure_diagnoses (id, cluster_id, status, provider, model, category, confidence, summary, root_cause, details, error, input_tokens, output_tokens, duration_ms, created_at, updated_at) VALUES (3, 5, 'completed', 'demo', 'demo', 'test-flakiness', 'medium', 'Strict mode violation on button role — multiple elements match because the component page renders three button variants for visual regression testing.', 'getByRole(''button'') resolves to 3 elements on the UI components test page. This occurs because the page intentionally renders primary, disabled, and loading button variants simultaneously. The test should scope its locator to a specific container or use a more specific selector.', '{"confidenceScore":65,"severity":"medium","affectedArea":"UI components / button","hypotheses":[{"category":"test-bug","likelihood":65,"rootCause":"getByRole(''button'') matches 3 rendered button variants, triggering a strict-mode violation; the locator needs scoping.","evidence":["Three button elements rendered by design (primary, disabled, loading) [ariaSnapshot]","Failure is deterministic, not intermittent [recurrenceFlakiness]"]}],"investigationSteps":["Confirm the page intentionally renders multiple button variants","Decide on a scoping strategy (name filter or container) with the component owner"],"evidence":["Error consistently occurs on the button spec page","Three button elements are rendered by design (primary, disabled, loading variants)","Failure is deterministic, not intermittent"],"suggestedFix":{"description":"Scope the locator to the specific button variant container, or use getByRole with a name filter.","file":"tests/ui/button.spec.ts","code":"await page.getByRole(''button'', { name: ''Primary'' }).click();"},"preventionTips":["Use unique aria-labels on components in visual regression pages","Scope locators to a parent element when multiple matches are expected","Add data-testid attributes to disambiguate similar elements"]}', NULL, 870, 290, 1950, 1745573400, 1745573400);
INSERT INTO failure_diagnoses (id, cluster_id, status, provider, model, category, confidence, summary, root_cause, details, error, input_tokens, output_tokens, duration_ms, created_at, updated_at) VALUES (4, 7, 'completed', 'demo', 'demo', 'infrastructure', 'high', 'Mobile page navigation fails with timeout — the Safari page load takes more than 30 seconds on CI, suggesting slow network or resource-heavy page.', 'page.goto timeout (30000ms) exceeded during mobile Safari tests. The navigation endpoint loads heavy assets (images, JS bundles) that are not optimized for mobile connections. Combined with CI network variability, this consistently exceeds the default timeout.', '{"confidenceScore":78,"severity":"high","affectedArea":"mobile navigation","hypotheses":[{"category":"infrastructure","likelihood":78,"rootCause":"Heavy unoptimized assets push mobile Safari page load past the 30s goto timeout on CI networks.","evidence":["Timeout on main navigation load, not subsequent interactions [steps]","Only affects the mobile Safari browser config [browserDistribution]"]},{"category":"environment","likelihood":35,"rootCause":"CI network throttling specific to the mobile project profile.","evidence":["Page load time correlates with asset bundle deployments [webVitals]"]}],"investigationSteps":["Measure the page weight and largest-contentful-paint on the mobile profile","Compare goto timing on a local mobile emulation vs CI"],"evidence":["Timeout occurs on main navigation page load, not on subsequent interactions","Only affects the mobile Safari browser config","Page load time correlates with asset bundle size deployments"],"suggestedFix":{"description":"Increase the navigation timeout for mobile tests and consider lazy-loading non-critical assets on the target page.","file":"tests/mobile/navigation.spec.ts","code":"await page.goto(''https://app.example.com'', { timeout: 60000 });"},"preventionTips":["Set browser-specific timeouts via Playwright config projects","Optimize page load performance for mobile (code splitting, image optimization)","Add a smoke test that verifies page load under 10s in CI"]}', NULL, 1100, 340, 2650, 1745573400, 1745573400);
